INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Define relative atomic mass (A_r).', 'The weighted mean mass of an atom of an element relative to 1/12 the mass of a carbon-12 atom.', 1, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Outline the four stages of time-of-flight (TOF) mass spectrometry.', 'Ionisation (electron impact or electrospray), acceleration by an electric field to constant kinetic energy, ion drift through a flight tube, and detection where ions gain electrons and the time of flight gives mass.', 2, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Define first ionisation energy.', 'The enthalpy change when one mole of gaseous atoms loses one electron each to form one mole of gaseous 1+ ions: X(g) -> X+(g) + e-.', 3, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Why is the first ionisation energy of aluminium lower than magnesium?', 'Aluminium''s outer electron is in a 3p sub-shell, which is higher in energy than Mg''s 3s sub-shell, so it is held less strongly and easier to remove.', 4, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Give the electron configuration of Fe and Fe3+.', 'Fe: 1s2 2s2 2p6 3s2 3p6 3d6 4s2. Fe3+: 1s2 2s2 2p6 3s2 3p6 3d5 (4s electrons are lost first).', 5, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'State the ideal gas equation with units.', 'pV = nRT, where p is pressure (Pa), V is volume (m^3), n is moles, R = 8.31 J K^-1 mol^-1, T is temperature (K).', 6, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Define percentage atom economy.', '% atom economy = (M_r of desired product / sum of M_r of all products) x 100. It measures the efficiency of incorporating reactant atoms into the desired product.', 7, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'What is the shape and bond angle around an NH3 molecule?', 'Trigonal pyramidal with bond angle 107 degrees. There are 3 bonding pairs and 1 lone pair, and the lone pair compresses the bond angle from 109.5. <svg viewBox="0 0 120 100" width="110" height="90" style="display:block;margin:6px auto"><circle cx="60" cy="40" r="6" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="2"/><text x="55" y="44" font-size="10" fill="#0B1E3F">N</text><line x1="60" y1="46" x2="30" y2="80" stroke="#0B1E3F" stroke-width="2"/><line x1="60" y1="46" x2="60" y2="85" stroke="#0B1E3F" stroke-width="2"/><line x1="60" y1="46" x2="90" y2="80" stroke="#0B1E3F" stroke-width="2"/><text x="22" y="92" font-size="10" fill="#0B1E3F">H</text><text x="56" y="97" font-size="10" fill="#0B1E3F">H</text><text x="92" y="92" font-size="10" fill="#0B1E3F">H</text></svg>', 8, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Why does H2O have a much higher boiling point than H2S?', 'H2O molecules form hydrogen bonds (O-H...O), which are much stronger than the London/permanent dipole forces between H2S molecules, so more energy is needed to separate them.', 9, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'State Hess''s Law.', 'The total enthalpy change for a reaction is independent of the route taken, provided the initial and final conditions are the same.', 10, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Write the calorimetry equation and define each term.', 'q = mc(deltaT), where q is heat energy (J), m is mass of solution/water (g), c is specific heat capacity (4.18 J g^-1 K^-1 for water), and deltaT is temperature change (K).', 11, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Why is mean bond enthalpy approximate?', 'It is averaged over a range of compounds, but the actual bond strength varies slightly with the molecular environment, so calculated enthalpy changes using mean bond enthalpies differ from experimental values.', 12, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'Sketch the Maxwell-Boltzmann distribution and label key features.', 'A skewed curve starting at the origin, peaking at the most probable energy, with no molecules at zero energy. Area under curve = total molecules. Molecules with E >= Ea (shaded right tail) can react. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="100" x2="190" y2="100" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="100" x2="20" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M20,100 Q60,15 100,55 T190,98" fill="none" stroke="#0B1E3F" stroke-width="2"/><line x1="130" y1="100" x2="130" y2="20" stroke="#0B1E3F" stroke-width="1" stroke-dasharray="3,2"/><text x="120" y="14" font-size="9" fill="#0B1E3F">Ea</text><text x="80" y="115" font-size="9" fill="#0B1E3F">Energy</text></svg>', 13, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'How does a catalyst affect the Maxwell-Boltzmann distribution?', 'A catalyst lowers the activation energy, so a greater proportion of molecules have energy >= Ea. The distribution shape itself is unchanged.', 14, 'alevel'),
  ('Chemistry', 'AQA', 'P1', 'Physical Chemistry I', 'What is meant by an empirical formula?', 'The simplest whole-number ratio of atoms of each element in a compound, e.g. CH2O for glucose.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Write the rate equation for a reaction first order in A and second order in B.', 'rate = k[A][B]^2; overall order = 3.', 1, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'State the units of k for a third-order reaction.', 'mol^-2 dm^6 s^-1.', 2, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'State the Arrhenius equation.', 'k = A e^(-Ea/RT). A linear form is ln k = ln A - Ea/(RT), so a plot of ln k against 1/T has gradient -Ea/R.', 3, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Define Le Chatelier''s principle.', 'When a system at dynamic equilibrium is disturbed by a change in conditions, the position of equilibrium shifts to oppose that change.', 4, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Why does a catalyst not change Kc?', 'A catalyst speeds up the forward and reverse reactions equally, reaching equilibrium faster but without altering the equilibrium position or Kc.', 5, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'For N2(g) + 3H2(g) <=> 2NH3(g), write Kp.', 'Kp = (p(NH3))^2 / (p(N2) x (p(H2))^3).', 6, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Why are conditions for the Haber process a compromise?', 'High pressure (~200 atm) favours forward reaction but is expensive and dangerous; low temperature favours yield but slows rate, so 450 C is used with an iron catalyst as a balance between yield, rate and cost.', 7, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Define standard enthalpy of lattice formation.', 'The enthalpy change when one mole of an ionic solid is formed from its gaseous ions under standard conditions; always exothermic.', 8, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Why are theoretical and experimental lattice enthalpies sometimes different?', 'Theoretical values assume a purely ionic model with point charges; greater differences indicate covalent character (e.g. AgCl, AgI), which the model does not account for.', 9, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'State the Gibbs free energy equation and the feasibility criterion.', 'deltaG = deltaH - T(deltaS). A reaction is feasible when deltaG <= 0.', 10, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Define the acid dissociation constant Ka and pKa.', 'Ka = [H+][A-]/[HA] for HA <=> H+ + A-. pKa = -log10(Ka). Smaller pKa means a stronger acid.', 11, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'How does a buffer of CH3COOH/CH3COO- resist added acid?', 'Added H+ reacts with CH3COO-: CH3COO- + H+ -> CH3COOH. The conjugate base mops up extra protons, so [H+] and pH change only slightly.', 12, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Sketch the titration curve for strong acid + strong base and label the equivalence pH.', 'pH starts low (~1), rises slowly, then jumps sharply through pH 7 at the equivalence point, levelling off near 13. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="105" x2="190" y2="105" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="105" x2="20" y2="10" stroke="#0B1E3F" stroke-width="1.5"/><path d="M20,95 L90,85 L100,20 L180,15" fill="none" stroke="#0B1E3F" stroke-width="2"/><text x="2" y="60" font-size="9" fill="#0B1E3F">pH</text><text x="80" y="118" font-size="9" fill="#0B1E3F">V base</text><circle cx="95" cy="55" r="2" fill="#0B1E3F"/><text x="100" y="55" font-size="8" fill="#0B1E3F">7</text></svg>', 13, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Define standard electrode potential.', 'The EMF of a half-cell connected to a standard hydrogen electrode under standard conditions (298 K, 1 mol dm^-3 ions, 100 kPa). Measured with a high-resistance voltmeter.', 14, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'How is cell EMF calculated from electrode potentials?', 'E_cell = E(positive electrode) - E(negative electrode), where the positive electrode is the more positive (reduction) half-cell.', 15, 'alevel'),
  ('Chemistry', 'AQA', 'P2', 'Physical Chemistry II', 'Why is the entropy of gases higher than liquids or solids?', 'Gas particles have much greater translational freedom and many more accessible microstates, so the system is more disordered.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Explain the trend in atomic radius across Period 3.', 'Atomic radius decreases. Nuclear charge increases while electrons are added to the same shell, so shielding is roughly constant and effective nuclear charge rises, pulling electrons closer.', 1, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Why is the first ionisation energy of S lower than P?', 'In S, two 3p electrons share an orbital and repel; one is lost more easily than the unpaired 3p electron of P, despite the higher nuclear charge.', 2, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Explain melting point trend across Period 3.', 'Na to Al: metallic, melting point rises with charge density. Si: giant covalent, very high MP. P, S, Cl: simple molecular, low MP depending on size of molecule. Ar: monatomic, lowest MP.', 3, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Describe the trend in reactivity down Group 2.', 'Reactivity increases. Atomic radius increases and shielding rises, so the outer electrons are lost more easily despite increasing nuclear charge.', 4, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Give equation for Mg burning in steam.', 'Mg(s) + H2O(g) -> MgO(s) + H2(g), bright white flame.', 5, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Explain the solubility trend of Group 2 hydroxides.', 'Solubility increases down the group: Mg(OH)2 sparingly soluble, Ba(OH)2 soluble. Lattice enthalpy decreases faster than enthalpy of hydration, so the dissolving process is more energetically favourable.', 6, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'How does thermal stability of Group 2 carbonates change down the group?', 'Stability increases. Larger cations have lower charge density, polarising the carbonate ion less, so more energy (higher temperature) is needed to decompose them.', 7, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Give the flame test colours for Li, Na, K, Ca, Sr, Ba.', 'Li: crimson; Na: yellow; K: lilac; Ca: brick red; Sr: red; Ba: pale green.', 8, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Why does halogen reactivity decrease down Group 7?', 'Atomic radius increases and shielding rises, so the attraction for an extra electron weakens — halogens become less effective oxidising agents going down.', 9, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Give observations and ionic equation for adding Cl2 to KBr(aq).', 'Solution turns orange/brown. Cl2 + 2Br- -> 2Cl- + Br2 (chlorine displaces bromide because Cl2 is a stronger oxidising agent).', 10, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'How are halide ions distinguished using AgNO3 and NH3?', 'Cl-: white ppt, dissolves in dilute NH3. Br-: cream ppt, dissolves in concentrated NH3. I-: pale yellow ppt, insoluble in concentrated NH3.', 11, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Why do halides become better reducing agents down the group?', 'Ionic radius increases and outer electrons are further from the nucleus with more shielding, so they are lost more easily.', 12, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Give the equation and conditions for chlorine''s disproportionation in cold dilute NaOH.', 'Cl2 + 2NaOH -> NaCl + NaClO + H2O. Cl is +0 in Cl2, becoming -1 (NaCl) and +1 (NaClO) — both oxidised and reduced.', 13, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'What is observed when concentrated H2SO4 is added to solid NaI?', 'Steamy fumes of HI; further reduction gives black solid I2, purple/violet vapour, yellow S, red-brown SO2 and H2S smell of rotten eggs (I- is a strong reducing agent).', 14, 'alevel'),
  ('Chemistry', 'AQA', 'I1', 'Inorganic Chemistry I', 'Why is chlorine added to drinking water despite its toxicity?', 'It kills bacteria and prevents waterborne disease. The benefit (preventing illness like cholera) outweighs the small risk of chlorinated organic by-products.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Why does MgO have a higher melting point than Na2O?', 'Mg2+ has a higher charge density (smaller, 2+) than Na+, so the ionic bonds in MgO''s lattice are stronger, requiring more energy to break.', 1, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Give the products and pH when SO3 reacts with water.', 'SO3 + H2O -> H2SO4. Resulting pH ~ 0 (strongly acidic).', 2, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Why does AlCl3 have a low melting point compared to NaCl?', 'AlCl3 forms covalent dimers (Al2Cl6) due to Al3+ polarising Cl- strongly; only weak intermolecular forces operate, unlike NaCl''s giant ionic lattice.', 3, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Define a transition metal.', 'A d-block element that forms at least one stable ion with a partially filled d sub-shell. Sc and Zn are excluded (Sc3+ has empty d, Zn2+ has full d).', 4, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Why are transition metal ions usually coloured?', 'Ligands split the d-orbitals into two sets; electrons absorb visible light to be promoted (deltaE = hf), and the complementary colour is transmitted.', 5, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Define a ligand and coordination number.', 'A ligand is a molecule or ion that donates a lone pair to a metal ion to form a dative covalent bond. Coordination number is the total number of dative bonds to the central ion.', 6, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Give an example of a bidentate ligand.', 'Ethane-1,2-diamine (en, H2NCH2CH2NH2) or ethanedioate (C2O4^2-); each donates two lone pairs to the metal.', 7, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Sketch the shapes of [Cu(H2O)6]2+ and [CoCl4]2-.', 'Octahedral (90 degrees) and tetrahedral (109.5 degrees) respectively. <svg viewBox="0 0 200 100" width="180" height="90" style="display:block;margin:6px auto"><circle cx="50" cy="50" r="6" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="2"/><line x1="50" y1="44" x2="50" y2="20" stroke="#0B1E3F" stroke-width="1.5"/><line x1="50" y1="56" x2="50" y2="80" stroke="#0B1E3F" stroke-width="1.5"/><line x1="44" y1="50" x2="20" y2="50" stroke="#0B1E3F" stroke-width="1.5"/><line x1="56" y1="50" x2="80" y2="50" stroke="#0B1E3F" stroke-width="1.5"/><line x1="46" y1="46" x2="30" y2="35" stroke="#0B1E3F" stroke-width="1.5" stroke-dasharray="3,2"/><line x1="54" y1="54" x2="70" y2="65" stroke="#0B1E3F" stroke-width="1.5"/><circle cx="150" cy="50" r="6" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="2"/><line x1="150" y1="44" x2="150" y2="20" stroke="#0B1E3F" stroke-width="1.5"/><line x1="146" y1="56" x2="125" y2="80" stroke="#0B1E3F" stroke-width="1.5"/><line x1="154" y1="56" x2="175" y2="80" stroke="#0B1E3F" stroke-width="1.5"/><line x1="156" y1="46" x2="178" y2="35" stroke="#0B1E3F" stroke-width="1.5" stroke-dasharray="3,2"/></svg>', 8, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'What is cisplatin and why does it work?', 'cis-[Pt(NH3)2Cl2], a square planar Pt(II) complex used as an anticancer drug. The cis isomer binds DNA at adjacent guanines, preventing replication; the trans isomer is ineffective.', 9, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Give the colour change when NaOH(aq) is added to Cu(II)(aq).', '[Cu(H2O)6]2+ (blue solution) + 2OH- -> Cu(OH)2(H2O)4 (pale blue precipitate) + 2H2O. Insoluble in excess NaOH.', 10, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'How does excess NH3 distinguish Cu2+ from Al3+?', 'Cu2+: pale blue ppt redissolves in excess NH3 to deep blue [Cu(NH3)4(H2O)2]2+. Al3+: white ppt does not redissolve in excess NH3.', 11, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Why are aqueous Fe3+ ions more acidic than Fe2+?', 'Fe3+ has a higher charge density, polarises water ligands more strongly, and weakens an O-H bond, making H+ release easier. Fe3+ solutions are pale yellow/brown and acidic; Fe2+ solutions are pale green and weakly acidic.', 12, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'How is the test for sulfate ions performed?', 'Add dilute HCl (to remove carbonate), then BaCl2(aq). A white precipitate of BaSO4 confirms sulfate.', 13, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Give the half-equation for MnO4- in acidic solution.', 'MnO4- + 8H+ + 5e- -> Mn2+ + 4H2O. Purple to colourless on reduction; used in titrations as self-indicator.', 14, 'alevel'),
  ('Chemistry', 'AQA', 'I2', 'Inorganic Chemistry II', 'Why is the chelate effect entropically favoured?', 'Substituting monodentate ligands by bidentate or polydentate ligands increases the number of free particles in solution (deltaS > 0), so deltaG becomes more negative.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Define structural isomerism.', 'Compounds with the same molecular formula but different structural formulae. Three types: chain, position, and functional group isomerism.', 1, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'When does E/Z isomerism arise?', 'When there is restricted rotation around a C=C double bond AND each carbon has two different groups attached. CIP priority rules assign E (groups on opposite sides) or Z (same side).', 2, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Define an enantiomer.', 'One of two non-superimposable mirror-image stereoisomers of a chiral molecule. They rotate plane-polarised light in equal but opposite directions.', 3, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Outline the mechanism for the chlorination of methane and give the propagation steps.', 'Free radical substitution: initiation Cl2 -> 2Cl. (UV); propagation Cl. + CH4 -> HCl + CH3., then CH3. + Cl2 -> CH3Cl + Cl.; termination by radical-radical combination.', 4, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'State Markownikoff''s rule.', 'When HX adds to an unsymmetrical alkene, H adds to the carbon with the most H atoms. The major product forms via the more stable (more substituted) carbocation intermediate.', 5, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'What test distinguishes alkenes from alkanes?', 'Bromine water: alkenes decolourise it from orange to colourless via electrophilic addition; alkanes do not react.', 6, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Give the structural formula and skeletal formula of ethanol.', 'CH3CH2OH. <svg viewBox="0 0 120 60" width="110" height="55" style="display:block;margin:6px auto"><line x1="20" y1="40" x2="55" y2="20" stroke="#0B1E3F" stroke-width="2"/><line x1="55" y1="20" x2="90" y2="40" stroke="#0B1E3F" stroke-width="2"/><text x="92" y="44" font-size="11" fill="#0B1E3F">OH</text></svg>', 7, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'How are primary, secondary and tertiary alcohols classified?', 'By the number of carbons attached to the C bonded to OH: 1 = primary, 2 = secondary, 3 = tertiary.', 8, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Reagents/conditions to oxidise primary alcohol to aldehyde vs to carboxylic acid?', 'Aldehyde: K2Cr2O7/H2SO4, distil out as it forms. Carboxylic acid: K2Cr2O7/H2SO4, heat under reflux with excess oxidant.', 9, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Compare SN1 and SN2 mechanisms.', 'SN2: one-step concerted, rate = k[RX][Nu], inversion of stereochemistry, favoured by primary halogenoalkanes. SN1: two-step via carbocation, rate = k[RX], racemisation, favoured by tertiary halogenoalkanes.', 10, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Why does the rate of nucleophilic substitution decrease in the order C-I > C-Br > C-Cl > C-F?', 'C-I has the lowest bond enthalpy (longest, weakest bond) so breaks most easily, despite C-F being most polar. Bond strength dominates.', 11, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Give the conditions for elimination from a halogenoalkane.', 'KOH (or NaOH) in ethanol, heat. The OH- acts as a base, removing a beta-hydrogen to form an alkene; in aqueous KOH, OH- acts as a nucleophile and substitutes instead.', 12, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'How is an aldehyde distinguished from a ketone using IR?', 'Both show C=O stretch ~1700 cm^-1, but only the aldehyde shows a weak C-H stretch at ~2720 cm^-1. Tollens'' reagent gives a silver mirror with aldehydes only.', 13, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'What does the M+1 peak in mass spectrometry indicate?', 'The presence of one or more 13C isotopes. The ratio of M+1 : M peak heights helps identify the number of carbons in the molecule.', 14, 'alevel'),
  ('Chemistry', 'AQA', 'O1', 'Organic Chemistry I', 'Why is addition polymerisation not green chemistry?', 'It uses non-renewable hydrocarbon feedstocks (alkenes from crude oil) and produces non-biodegradable polymers (e.g. poly(ethene)) that persist in the environment.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Outline nucleophilic addition of HCN to a carbonyl.', 'CN- attacks the delta+ C of C=O; the pi bond breaks and an alkoxide forms which is protonated by HCN to give a 2-hydroxynitrile (cyanohydrin). Product is a racemic mixture if a chiral C is formed.', 1, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'How are aldehydes distinguished from ketones using Tollens'' and Fehling''s?', 'Tollens'' (Ag(NH3)2+) gives a silver mirror with aldehydes only. Fehling''s (blue Cu2+ complex) gives a brick-red Cu2O ppt with aliphatic aldehydes only. Ketones show no change.', 2, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Describe the structure of benzene.', 'A planar regular hexagon of 6 carbons; each C is sp2 hybridised with a p-orbital perpendicular to the ring; p-orbitals overlap to form a delocalised pi system. <svg viewBox="0 0 100 100" width="90" height="90" style="display:block;margin:6px auto"><polygon points="50,10 87,30 87,72 50,92 13,72 13,30" fill="none" stroke="#0B1E3F" stroke-width="2"/><circle cx="50" cy="51" r="20" fill="none" stroke="#0B1E3F" stroke-width="1.5"/></svg>', 3, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Why is benzene more stable than the Kekule cyclohexa-1,3,5-triene model?', 'Hydrogenation of benzene releases ~152 kJ less energy than predicted; the delocalised pi system is more stable than three localised C=C bonds.', 4, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Give the electrophile and conditions for the nitration of benzene.', 'Electrophile: NO2+, generated from concentrated HNO3 + concentrated H2SO4 (catalyst). Conditions: 50 C. Product: nitrobenzene.', 5, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'How is the electrophile generated in Friedel-Crafts acylation?', 'CH3COCl + AlCl3 -> CH3CO+ + AlCl4-. The acylium ion CH3CO+ attacks benzene to form a phenyl ketone.', 6, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Why are amines basic, and why is ethylamine more basic than ammonia?', 'The N lone pair accepts H+. Ethylamine''s alkyl group is electron-donating (positive inductive), increasing electron density on N and stabilising the conjugate acid; aromatic amines (phenylamine) are weaker because the lone pair delocalises into the ring.', 7, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'How is phenylamine prepared from nitrobenzene?', 'Reduction with Sn (or Fe) and concentrated HCl, heated under reflux; then NaOH(aq) to liberate the free amine.', 8, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'What is a zwitterion?', 'A dipolar ion of an amino acid carrying a positive (-NH3+) and a negative (-COO-) charge but no overall charge. Forms at the isoelectric point.', 9, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Compare addition and condensation polymerisation.', 'Addition: monomers contain C=C, no by-product, e.g. poly(ethene). Condensation: two functional groups react and a small molecule (H2O or HCl) is eliminated, e.g. polyesters and polyamides.', 10, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Why are condensation polymers usually more biodegradable than addition polymers?', 'Polar ester/amide linkages can be hydrolysed by acids, bases or enzymes; addition polymers have non-polar C-C backbones that resist hydrolysis.', 11, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'In 1H NMR, how many peaks does ethanol show before and after a D2O shake?', 'Before D2O: 3 peaks (CH3, CH2, OH). After D2O: 2 peaks — the OH proton exchanges with D and disappears.', 12, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'State the n+1 rule.', 'A 1H NMR signal is split into n+1 peaks by n equivalent neighbouring (non-equivalent) hydrogen atoms.', 13, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Define Rf in TLC.', 'Rf = distance moved by spot / distance moved by solvent front. It is constant for a given compound under fixed conditions.', 14, 'alevel'),
  ('Chemistry', 'AQA', 'O2', 'Organic Chemistry II', 'Why is GC-MS more powerful than GC alone?', 'GC separates components by retention time; the mass spectrometer then identifies each by its fragmentation pattern, giving both quantitative separation and qualitative identification.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Define the term isotope.', 'Atoms of the same element with the same number of protons but different numbers of neutrons.', 1, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Outline how a TOF mass spectrometer determines mass.', 'Sample is ionised, accelerated to constant kinetic energy, drifts through a flight tube, and detected. Lighter ions arrive first; m/z is calculated from time of flight.', 2, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Give the order of filling for 3d and 4s sub-shells.', '4s fills before 3d (4s is lower in energy when empty), but 4s electrons are removed first when forming ions.', 3, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Why does first ionisation energy generally increase across Period 3?', 'Nuclear charge increases, atomic radius decreases, shielding stays similar, so the outer electron is held more strongly.', 4, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Explain the big jump between successive IEs as evidence for shells.', 'A large jump occurs when the next electron comes from a shell closer to the nucleus, where it is held much more strongly. The position of the jump indicates the group number.', 5, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Why is NaCl soluble in water but insoluble in hexane?', 'Polar water molecules surround Na+ and Cl-, releasing energy that compensates for breaking the lattice. Non-polar hexane cannot solvate the ions, so dissolving is not energetically favourable.', 6, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'What are the bond angle and shape of CH4 and SF6?', 'CH4: tetrahedral, 109.5 degrees (4 bonding pairs). SF6: octahedral, 90 degrees (6 bonding pairs).', 7, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Sketch the shape of methane.', 'Tetrahedral, all H-C-H angles 109.5 degrees. <svg viewBox="0 0 120 100" width="110" height="90" style="display:block;margin:6px auto"><circle cx="60" cy="50" r="6" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="2"/><text x="55" y="54" font-size="10" fill="#0B1E3F">C</text><line x1="60" y1="44" x2="60" y2="15" stroke="#0B1E3F" stroke-width="2"/><line x1="55" y1="54" x2="25" y2="80" stroke="#0B1E3F" stroke-width="2"/><line x1="65" y1="54" x2="95" y2="80" stroke="#0B1E3F" stroke-width="2"/><line x1="60" y1="56" x2="60" y2="85" stroke="#0B1E3F" stroke-width="2" stroke-dasharray="3,2"/></svg>', 8, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'List the three types of intermolecular force in order of strength.', 'London (induced dipole-dipole) < permanent dipole-dipole < hydrogen bonding. All weaker than covalent or ionic bonds.', 9, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Why does ice have a lower density than liquid water?', 'In ice, hydrogen bonds hold water molecules in an open hexagonal lattice with large gaps; melting collapses the structure, packing molecules closer.', 10, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Define electronegativity.', 'The ability of an atom in a covalent bond to attract the bonding pair of electrons. F is the most electronegative element; Pauling scale.', 11, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Define standard enthalpy of combustion.', 'The enthalpy change when one mole of a substance is completely burned in oxygen under standard conditions (100 kPa, 298 K, all substances in their standard states).', 12, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'State Hess''s Law and how it lets us calculate enthalpy changes.', 'The total enthalpy change is independent of route. Using a Hess cycle, the enthalpy of an unmeasurable reaction is found by combining measured enthalpies of formation or combustion.', 13, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Why does calorimetry usually give a lower deltaH than the textbook?', 'Heat losses to the surroundings, incomplete combustion, evaporation of fuel/water, and non-standard conditions all reduce the recorded temperature rise.', 14, 'alevel'),
  ('Chemistry', 'Edexcel', 'T1', 'Atomic Structure, Bonding and Energetics', 'Compare bond enthalpy values for C-C, C=C, C(triple bond)C.', 'C-C ~ 347 kJ mol^-1, C=C ~ 612, C(triple bond)C ~ 838. More shared electron pairs give a stronger, shorter bond.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'List the factors affecting reaction rate.', 'Concentration (or pressure for gases), temperature, surface area, presence of a catalyst, and (for photochemical reactions) light intensity.', 1, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Sketch the Maxwell-Boltzmann distribution at two temperatures.', 'At higher T, peak shifts right and lowers, with a greater fraction of molecules above Ea. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="100" x2="190" y2="100" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="100" x2="20" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M20,100 Q55,20 90,55 T190,98" fill="none" stroke="#0B1E3F" stroke-width="2"/><path d="M20,100 Q80,40 120,65 T190,95" fill="none" stroke="#0B1E3F" stroke-width="2" stroke-dasharray="4,3"/><line x1="135" y1="100" x2="135" y2="25" stroke="#0B1E3F" stroke-width="1" stroke-dasharray="3,2"/><text x="125" y="20" font-size="9" fill="#0B1E3F">Ea</text></svg>', 2, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Why does a small temperature rise dramatically increase rate?', 'A 10 K rise typically doubles the proportion of molecules with E >= Ea (exponential dependence in Arrhenius), so collision-with-Ea frequency rises sharply.', 3, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'For the rate equation rate = k[A]^2[B], state the overall order and the units of k.', 'Overall order = 3. Units of k: mol^-2 dm^6 s^-1.', 4, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'How is the order with respect to a reactant determined experimentally?', 'Plot concentration vs time and analyse the half-life (constant for first order) or use initial-rates: change one [reactant] at a time and see how rate changes (doubling [A] doubling rate = first order).', 5, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Write the linear form of the Arrhenius equation.', 'ln k = -Ea/(RT) + ln A. Plot ln k against 1/T; gradient = -Ea/R, intercept = ln A.', 6, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Define dynamic equilibrium.', 'A closed-system equilibrium where forward and reverse reactions occur at equal rates, so concentrations of all species remain constant.', 7, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'How does temperature affect Kc?', 'For an exothermic forward reaction, Kc decreases as T rises. For endothermic, Kc increases with T. Catalysts and pressure changes do not alter Kc.', 8, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Write Kc for 2SO2(g) + O2(g) <=> 2SO3(g).', 'Kc = [SO3]^2 / ([SO2]^2 [O2]). Units: mol^-1 dm^3.', 9, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Assign oxidation states in K2Cr2O7.', 'K = +1, O = -2; sum = 0. So 2(+1) + 2Cr + 7(-2) = 0, giving Cr = +6.', 10, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Balance the half-equation for MnO4- in acidic solution.', 'MnO4- + 8H+ + 5e- -> Mn2+ + 4H2O. Mn goes from +7 (purple) to +2 (colourless).', 11, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Define standard electrode potential.', 'The voltage of a half-cell measured against a standard hydrogen electrode (Pt, H2 at 100 kPa, 1 mol dm^-3 H+) at 298 K with all ions at 1 mol dm^-3.', 12, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'How is cell EMF calculated and what does a positive E_cell indicate?', 'E_cell = E(reduction) - E(oxidation), or right-hand minus left-hand electrode in the conventional cell diagram. Positive E_cell means the reaction is feasible under standard conditions.', 13, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'Why might a reaction with positive E_cell still not occur?', 'High activation energy may make it kinetically slow, or non-standard concentrations shift the actual potential. Standard E values say nothing about reaction rate.', 14, 'alevel'),
  ('Chemistry', 'Edexcel', 'T2', 'Kinetics, Equilibrium and Redox', 'What is the rate-determining step?', 'The slowest step in a multi-step mechanism; only species that appear in or before this step appear in the rate equation.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Explain melting point trend across Period 3.', 'Na to Al: metallic, MP rises with charge. Si: giant covalent, very high. P4, S8, Cl2: simple molecular. Ar: monatomic, lowest. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="100" x2="190" y2="100" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="100" x2="20" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><polyline points="30,80 50,65 70,55 90,15 110,75 130,85 150,90 170,95" fill="none" stroke="#0B1E3F" stroke-width="2"/><text x="2" y="60" font-size="9" fill="#0B1E3F">MP</text><text x="80" y="115" font-size="9" fill="#0B1E3F">Period 3</text></svg>', 1, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Give equation and observation for SiO2 with NaOH(aq).', 'SiO2 + 2NaOH -> Na2SiO3 + H2O (slow at room temperature, faster on heating). Acidic oxide.', 2, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Why does PCl5 fume in moist air?', 'It hydrolyses rapidly: PCl5 + 4H2O -> H3PO4 + 5HCl. Steamy fumes of HCl are observed.', 3, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Describe the reactions of Group 1 metals with water (going down the group).', 'Reactivity increases. Li: gentle fizzing. Na: melts into a ball, fizzes. K: lilac flame. Rb/Cs: explosive. All form M+ + OH- + 1/2 H2.', 4, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Why does first ionisation energy decrease down Group 2?', 'Atomic radius and shielding both increase, outweighing the rise in nuclear charge, so outer electrons are held less strongly.', 5, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Order Group 2 carbonates by thermal stability.', 'MgCO3 < CaCO3 < SrCO3 < BaCO3. Larger cations polarise the carbonate ion less, so more energy needed to decompose.', 6, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'How do Group 2 sulfate and hydroxide solubilities trend?', 'Sulfate solubility decreases down the group (BaSO4 insoluble — basis for sulfate test). Hydroxide solubility increases (Mg(OH)2 sparingly, Ba(OH)2 readily).', 7, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'How does concentrated H2SO4 react with NaCl, NaBr, NaI?', 'NaCl: HCl gas (acid-base only). NaBr: HBr + Br2 + SO2 (mild reduction). NaI: HI + I2 + H2S + S (strong reduction). Reducing power increases down the group.', 8, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Outline the silver nitrate test for halides.', 'Add HNO3 then AgNO3(aq). Cl-: white ppt, soluble in dilute NH3. Br-: cream, soluble in concentrated NH3. I-: pale yellow, insoluble in NH3.', 9, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Define a transition element.', 'A d-block element forming at least one stable ion with a partially filled d sub-shell. Sc and Zn are excluded.', 10, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Why are transition metals good catalysts?', 'They can change oxidation state and provide a surface (heterogeneous) or alternative pathway with a lower Ea via complex formation (homogeneous).', 11, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Give colour and formula for Cu in three common environments.', '[Cu(H2O)6]2+ pale blue (aq); Cu(OH)2 pale blue ppt; [Cu(NH3)4(H2O)2]2+ deep blue solution after excess NH3.', 12, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'How do you test for ammonium ions?', 'Add NaOH(aq) and warm. NH3 gas evolved turns damp red litmus blue.', 13, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'How does ligand substitution change colour for Co(II)?', '[Co(H2O)6]2+ (pink) + 4Cl- <=> [CoCl4]2- (blue) + 6H2O. Equilibrium driven by chloride concentration; classic example used in cobalt chloride indicators.', 14, 'alevel'),
  ('Chemistry', 'Edexcel', 'T3', 'Inorganic Chemistry', 'Why is the chelate effect entropically driven?', 'Substituting monodentate ligands with bidentate or polydentate ligands increases the number of free particles, raising deltaS and making deltaG more negative.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'State the IUPAC rule for numbering carbons.', 'Number to give the principal functional group the lowest possible locant; then halogens or other substituents, listed alphabetically.', 1, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Define homologous series.', 'A series of organic compounds with the same general formula and functional group, differing by CH2, with similar chemistry and a gradual trend in physical properties.', 2, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'When does optical isomerism occur?', 'When a carbon atom has four different groups attached (a chiral centre), giving non-superimposable mirror-image enantiomers that rotate plane-polarised light in opposite directions.', 3, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Why does boiling point increase as alkanes get longer?', 'Larger alkanes have more electrons and a greater surface area, increasing London dispersion forces, so more energy is needed to boil.', 4, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Give the propagation steps for the chlorination of methane.', 'Cl. + CH4 -> HCl + CH3.; CH3. + Cl2 -> CH3Cl + Cl.', 5, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'State Markownikoff''s rule and explain it.', 'In HX addition to an unsymmetric alkene, H adds to the carbon with more H atoms. The major product comes from the more stable (more alkyl-substituted) carbocation.', 6, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Give the test and observation for a C=C double bond.', 'Bromine water turns from orange/yellow to colourless via electrophilic addition forming a 1,2-dibromoalkane.', 7, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Sketch the curly-arrow electrophilic addition of HBr to ethene.', 'H attacks the C=C pi bond; Br- attacks the resulting carbocation. <svg viewBox="0 0 200 80" width="180" height="75" style="display:block;margin:6px auto"><line x1="40" y1="35" x2="80" y2="35" stroke="#0B1E3F" stroke-width="2"/><line x1="40" y1="42" x2="80" y2="42" stroke="#0B1E3F" stroke-width="2"/><text x="20" y="42" font-size="11" fill="#0B1E3F">H2C</text><text x="82" y="42" font-size="11" fill="#0B1E3F">CH2</text><path d="M60,30 Q90,5 130,30" fill="none" stroke="#0B1E3F" stroke-width="1.5" marker-end="url(#a)"/><text x="135" y="42" font-size="11" fill="#0B1E3F">H-Br</text></svg>', 8, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Compare aqueous and ethanolic KOH on a halogenoalkane.', 'Aqueous KOH: nucleophilic substitution -> alcohol. Ethanolic KOH: elimination -> alkene + H2O + KX.', 9, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Why does C-I react faster than C-Cl in nucleophilic substitution?', 'C-I has the lowest bond enthalpy, so it breaks more easily. Bond strength dominates over polarity in determining rate.', 10, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Reagents to oxidise a primary alcohol to a carboxylic acid?', 'Acidified K2Cr2O7 (orange to green), heated under reflux with excess oxidant.', 11, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'How is an ester made from an alcohol?', 'React with a carboxylic acid in concentrated H2SO4 catalyst, heated under reflux. e.g. CH3COOH + CH3CH2OH <=> CH3COOC2H5 + H2O (esterification).', 12, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'How would IR distinguish between butanal and butanoic acid?', 'Butanal: sharp C=O ~ 1720 cm^-1, no broad O-H. Butanoic acid: C=O ~ 1710 cm^-1 plus broad O-H 2500-3300 cm^-1.', 13, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'How do mass spectra distinguish isomers?', 'Different fragmentation patterns produce different m/z peaks; for example, butan-2-one shows distinct alpha-cleavage fragments compared with butanal.', 14, 'alevel'),
  ('Chemistry', 'Edexcel', 'T4', 'Organic Chemistry I', 'Give one chemical test for primary, secondary and tertiary alcohols.', 'Acidified K2Cr2O7: primary and secondary turn from orange to green; tertiary stays orange. Distil to isolate aldehyde (primary) vs ketone (secondary).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Define lattice enthalpy of formation.', 'The enthalpy change when one mole of an ionic compound forms from its gaseous ions under standard conditions; always exothermic.', 1, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'List the steps in a Born-Haber cycle for NaCl.', 'Atomisation of Na, ionisation of Na, atomisation of 1/2Cl2, electron affinity of Cl, lattice formation of NaCl. Sum equals deltaH_f of NaCl.', 2, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Why is the lattice enthalpy of MgO larger than NaCl?', 'Mg2+ and O2- have higher charges and smaller ionic radii than Na+ and Cl-, giving stronger electrostatic attraction between ions.', 3, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Why might experimental and theoretical lattice enthalpies differ?', 'Theoretical model assumes purely ionic point charges. Differences indicate covalent character; e.g. AgI has more covalent character than predicted, so the experimental |LE| is greater.', 4, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'What sign does deltaS have when a solid dissolves to form ions?', 'Usually positive: ions disperse and become hydrated, so disorder increases. Sometimes slightly negative if hydration shells are highly ordered.', 5, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'State the Gibbs equation and feasibility condition.', 'deltaG = deltaH - T(deltaS). Reaction is thermodynamically feasible when deltaG <= 0.', 6, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'For an endothermic reaction with positive deltaS, when is it feasible?', 'When T(deltaS) > deltaH, i.e. above T = deltaH/deltaS; deltaG becomes negative at high temperatures.', 7, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Define pH and the ionic product of water.', 'pH = -log10[H+]. Kw = [H+][OH-] = 1.00 x 10^-14 mol^2 dm^-6 at 298 K. Pure water has [H+] = 10^-7, pH = 7.', 8, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Calculate pH of 0.10 mol dm^-3 ethanoic acid (Ka = 1.8 x 10^-5).', '[H+] = sqrt(Ka x [HA]) = sqrt(1.8e-5 x 0.10) ~ 1.34e-3. pH = -log10(1.34e-3) ~ 2.87.', 9, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'How do you make a buffer?', 'Mix a weak acid with its salt (e.g. CH3COOH + CH3COONa), or partly neutralise a weak acid with a strong base. The resulting mixture resists pH change on addition of small amounts of acid or base.', 10, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'State the Henderson-Hasselbalch equation.', 'pH = pKa + log10([A-]/[HA]). When [A-] = [HA], pH = pKa (the half-equivalence point of a weak-acid titration).', 11, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Sketch the titration curve for a weak acid + strong base.', 'Buffer region rises slowly; sharp rise around equivalence at pH > 7; salt of weak acid is alkaline. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="105" x2="190" y2="105" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="105" x2="20" y2="10" stroke="#0B1E3F" stroke-width="1.5"/><path d="M20,90 Q60,75 95,55 L105,25 Q150,15 180,12" fill="none" stroke="#0B1E3F" stroke-width="2"/><text x="2" y="60" font-size="9" fill="#0B1E3F">pH</text><text x="80" y="118" font-size="9" fill="#0B1E3F">V base</text><circle cx="100" cy="40" r="2" fill="#0B1E3F"/></svg>', 12, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Choose a suitable indicator for HCl + NH3 titration.', 'Methyl orange (pH range 3.1-4.4): the equivalence point pH is < 7 because NH4Cl is acidic. Phenolphthalein would change colour too late.', 13, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Define standard enthalpy of neutralisation.', 'The enthalpy change when an aqueous acid is neutralised by an aqueous base to produce one mole of water under standard conditions; for strong acid + strong base, ~ -57 kJ mol^-1.', 14, 'alevel'),
  ('Chemistry', 'Edexcel', 'T5', 'Thermodynamics, Acids & Bases', 'Why is enthalpy of neutralisation less exothermic for a weak acid?', 'Some energy is used to fully ionise the weak acid before neutralisation, so the overall enthalpy released is less negative than for a strong acid.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'Why is benzene more stable than predicted by the Kekule model?', 'Hydrogenation of benzene releases ~152 kJ less energy than three times that of cyclohexene; the delocalised pi system spreads electron density and lowers energy. <svg viewBox="0 0 100 100" width="90" height="90" style="display:block;margin:6px auto"><polygon points="50,10 87,30 87,72 50,92 13,72 13,30" fill="none" stroke="#0B1E3F" stroke-width="2"/><circle cx="50" cy="51" r="20" fill="none" stroke="#0B1E3F" stroke-width="1.5"/></svg>', 1, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'Give the electrophile in the bromination of benzene.', 'Br+ generated from Br2 with FeBr3 (or AlBr3) catalyst: Br2 + FeBr3 -> Br+ + FeBr4-.', 2, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'Why is phenol more reactive than benzene in electrophilic substitution?', 'A lone pair on the OH oxygen donates into the ring through resonance, increasing electron density at the 2- and 4-positions and stabilising the intermediate. No catalyst is needed for bromination.', 3, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'How is nitrobenzene reduced to phenylamine?', 'Tin (Sn) and concentrated HCl, heated under reflux; then NaOH(aq) to liberate the free amine.', 4, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'Why does NaBH4 reduce carbonyls but not C=C?', 'NaBH4 delivers H- to the delta+ carbon of polar C=O, but C=C is non-polar and unreactive towards hydride. Aldehydes -> primary alcohols; ketones -> secondary alcohols.', 5, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'Give the test that distinguishes aldehydes from ketones using 2,4-DNP first.', '2,4-DNP gives an orange/yellow ppt with both. Then Tollens'' reagent gives a silver mirror with aldehydes only; ketones do not react.', 6, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'Acyl chloride + alcohol gives what?', 'An ester + HCl. e.g. CH3COCl + CH3OH -> CH3COOCH3 + HCl. Faster and more complete than esterification with the carboxylic acid.', 7, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'Why are aromatic amines weaker bases than aliphatic amines?', 'In phenylamine the N lone pair delocalises into the benzene ring, so it is less available to accept a proton. Aliphatic amines have an electron-donating alkyl group enhancing N''s lone pair.', 8, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'What is the isoelectric point of an amino acid?', 'The pH at which the amino acid exists as a zwitterion (-NH3+, -COO-) with no net charge and zero migration in an electric field.', 9, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'How do polyesters form?', 'A diol + a dicarboxylic acid (or diacyl chloride) condenses, releasing H2O (or HCl) per ester bond, e.g. terylene from ethane-1,2-diol + benzene-1,4-dicarboxylic acid.', 10, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'What does the M+2 peak indicate in a mass spectrum?', 'Presence of an isotope two units heavier (e.g. Cl-37 about 1/3 as abundant as Cl-35; Br-81 about equal to Br-79). Helps identify halogens.', 11, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'List two key IR absorption ranges.', 'O-H (alcohols) broad 3230-3550 cm^-1; O-H (carboxylic acid) very broad 2500-3300; C=O 1680-1750; N-H 3300-3500.', 12, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'What three pieces of information does 1H NMR provide?', 'Number of peaks (chemically different H environments), peak area/integration (number of H in each environment), and splitting pattern (n+1 from neighbouring H).', 13, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'Why use TMS as a reference in NMR?', 'It gives a single sharp peak at 0 ppm, is chemically inert, volatile, and contains 12 equivalent H. Most protons appear at higher chemical shift.', 14, 'alevel'),
  ('Chemistry', 'Edexcel', 'T6', 'Advanced Organic & Analysis', 'What is HPLC and why use it?', 'High-Performance Liquid Chromatography separates non-volatile or thermally unstable compounds by partition between a polar/non-polar liquid mobile phase and a solid stationary phase under high pressure; faster and higher resolution than column chromatography.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Distinguish independent, dependent and control variables.', 'Independent: deliberately changed. Dependent: measured. Control: kept constant to ensure only the IV affects the DV.', 1, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'How is a 250 cm3 standard solution of a soluble solid prepared?', 'Weigh by difference; dissolve in a beaker with deionised water; transfer with washings to a 250 cm3 volumetric flask; make up to the line; invert to mix.', 2, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Explain accuracy vs precision.', 'Accuracy: closeness to true value (low systematic error). Precision: closeness of repeat results (low random error). A method can be precise but inaccurate.', 3, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'How is percentage uncertainty in a burette reading calculated?', '% uncertainty = (uncertainty x 2 / titre) x 100, doubling because two readings (initial and final) each have +/- 0.05 cm3 uncertainty.', 4, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'What is a concordant titre?', 'Repeat titres within +/- 0.10 cm3 of each other; only concordant values are averaged for the mean titre.', 5, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Sketch a reflux apparatus.', 'Round-bottom flask with anti-bumping granules under a vertical condenser open at the top, water in at the bottom and out at the top. <svg viewBox="0 0 120 140" width="110" height="130" style="display:block;margin:6px auto"><circle cx="60" cy="100" r="20" fill="none" stroke="#0B1E3F" stroke-width="2"/><rect x="48" y="30" width="24" height="60" fill="none" stroke="#0B1E3F" stroke-width="2"/><line x1="44" y1="50" x2="48" y2="50" stroke="#0B1E3F" stroke-width="2"/><line x1="72" y1="70" x2="78" y2="70" stroke="#0B1E3F" stroke-width="2"/></svg>', 6, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Why is reflux used in organic synthesis?', 'It allows prolonged heating without losing volatile reactants or products: vapour rises, condenses, and returns to the flask, increasing yield.', 7, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Outline the recrystallisation procedure.', 'Dissolve impure solid in minimum hot solvent, filter hot to remove insoluble impurities, cool slowly to crystallise the product, filter under reduced pressure, wash with cold solvent, dry.', 8, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'How is an Rf value calculated and what does it indicate?', 'Rf = distance moved by solute / distance moved by solvent front. Constant under fixed conditions, used to identify components by comparison with standards.', 9, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'What is the purpose of a hazard symbol risk assessment?', 'To identify hazards, evaluate risk, and outline control measures (e.g. fume hood, gloves, eye protection) before practical work begins.', 10, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Define percentage yield.', '% yield = (actual moles of product / theoretical moles) x 100. Limited by side reactions, incomplete reactions, and losses during purification.', 11, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Define atom economy.', '% atom economy = (M_r of desired product / sum of M_r of all products) x 100. Higher = more sustainable, less waste.', 12, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'How are systematic and random errors reduced?', 'Systematic: calibrate equipment, use better technique. Random: take repeats and average; use more sensitive equipment to reduce uncertainty.', 13, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Why is fractional distillation used to separate ethanol/water?', 'Ethanol (78 C) and water (100 C) have similar boiling points; the column provides repeated condensation/evaporation for efficient separation, reaching the azeotrope at ~96% ethanol.', 14, 'alevel'),
  ('Chemistry', 'OCR A', 'M1', 'Development of Practical Skills', 'Explain validity vs reliability.', 'Validity: data measure what you intended (correct procedure, controls). Reliability: results are consistent on repeating, indicating low random error.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Define relative isotopic mass.', 'The mass of one atom of a specific isotope relative to 1/12 the mass of a carbon-12 atom.', 1, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Calculate Ar of an element with isotopes 24 (78.6%), 25 (10.1%), 26 (11.3%).', 'Ar = (24 x 78.6 + 25 x 10.1 + 26 x 11.3) / 100 = 24.33.', 2, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'State Avogadro''s constant.', '6.02 x 10^23 mol^-1, the number of particles in one mole.', 3, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Give the ideal gas equation in SI units.', 'pV = nRT; p in Pa, V in m^3, T in K, R = 8.31 J K^-1 mol^-1.', 4, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'How is an empirical formula determined from % composition?', 'Divide each % by the element''s Ar to get moles, divide all by the smallest, then multiply to whole-number ratio.', 5, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Give the order of orbital filling up to 4p.', '1s, 2s, 2p, 3s, 3p, 4s, 3d, 4p (4s fills before 3d but is removed first).', 6, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Sketch the shapes of s, p and d orbitals.', 's = sphere; p = dumbbell along an axis; d = generally four lobes (e.g. dxy). <svg viewBox="0 0 200 60" width="180" height="55" style="display:block;margin:6px auto"><circle cx="40" cy="30" r="15" fill="none" stroke="#0B1E3F" stroke-width="2"/><text x="32" y="55" font-size="10" fill="#0B1E3F">s</text><ellipse cx="100" cy="20" rx="10" ry="14" fill="none" stroke="#0B1E3F" stroke-width="2"/><ellipse cx="100" cy="42" rx="10" ry="14" fill="none" stroke="#0B1E3F" stroke-width="2"/><text x="95" y="55" font-size="10" fill="#0B1E3F">p</text><ellipse cx="155" cy="20" rx="6" ry="10" fill="none" stroke="#0B1E3F" stroke-width="1.5"/><ellipse cx="170" cy="20" rx="6" ry="10" fill="none" stroke="#0B1E3F" stroke-width="1.5"/><ellipse cx="155" cy="42" rx="6" ry="10" fill="none" stroke="#0B1E3F" stroke-width="1.5"/><ellipse cx="170" cy="42" rx="6" ry="10" fill="none" stroke="#0B1E3F" stroke-width="1.5"/><text x="160" y="55" font-size="10" fill="#0B1E3F">d</text></svg>', 7, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Explain why ionic compounds are brittle.', 'Distortion brings like-charged ions adjacent; strong repulsion shatters the crystal along cleavage planes.', 8, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Give the shape and bond angle of NH3, H2O, CH4 and BF3.', 'NH3: trigonal pyramidal, 107. H2O: bent, 104.5. CH4: tetrahedral, 109.5. BF3: trigonal planar, 120.', 9, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Define electronegativity.', 'The ability of an atom in a covalent bond to attract a bonding pair of electrons; F is most electronegative (4.0 on Pauling scale).', 10, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Why does H2O have an unusually high boiling point?', 'Hydrogen bonds (O-H...O) between molecules require much more energy to break than the dipole-dipole forces in similar-mass molecules like H2S.', 11, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Define an oxidation state.', 'The charge an atom would have if all bonds were ionic. Used to track electron transfer in redox reactions.', 12, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Combine half-equations to balance Cu + HNO3 -> Cu2+ + NO + H2O.', '3Cu + 8H+ + 2NO3- -> 3Cu2+ + 2NO + 4H2O. Balance e- between 3Cu -> 3Cu2+ + 6e- and 2NO3- + 8H+ + 6e- -> 2NO + 4H2O.', 13, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'How is concentration in g dm^-3 converted to mol dm^-3?', 'Divide by molar mass (M_r): concentration (mol dm^-3) = mass conc (g dm^-3) / M_r.', 14, 'alevel'),
  ('Chemistry', 'OCR A', 'M2', 'Foundations in Chemistry', 'Give a key acid reaction with carbonate.', 'Acid + carbonate -> salt + water + CO2. e.g. 2HCl + CaCO3 -> CaCl2 + H2O + CO2 (effervescence test).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Explain the trend in first ionisation energy across Period 3.', 'Generally increases due to rising nuclear charge, decreasing radius and similar shielding. Anomalies at Al (3p higher than 3s) and S (paired 3p electron repulsion).', 1, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Give equation and observation for Mg + cold water.', 'Mg + 2H2O -> Mg(OH)2 + H2. Very slow; gas evolved over hours.', 2, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Why does thermal stability of Group 2 nitrates increase down the group?', 'Larger M2+ ions polarise NO3- less, so the N-O bond is weaker, and more energy is needed to decompose to oxide + NO2 + O2.', 3, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Give flame test colours for Group 2 metals.', 'Mg: no characteristic colour. Ca: brick red. Sr: crimson red. Ba: pale green/apple.', 4, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'How does halogen reactivity change down Group 7?', 'Decreases. Larger atoms with more shielding attract an extra electron less strongly, so they are weaker oxidising agents.', 5, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Define standard enthalpy of formation.', 'The enthalpy change when one mole of a compound forms from its constituent elements in their standard states under standard conditions (100 kPa, 298 K).', 6, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Sketch an energy profile for an exothermic reaction with Ea labelled.', 'Reactants higher than products; activation energy hump between. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="100" x2="190" y2="100" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="100" x2="20" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M30,55 Q90,5 120,55 L170,75" fill="none" stroke="#0B1E3F" stroke-width="2"/><line x1="30" y1="55" x2="60" y2="55" stroke="#0B1E3F" stroke-width="1" stroke-dasharray="3,2"/><text x="65" y="35" font-size="9" fill="#0B1E3F">Ea</text><text x="20" y="50" font-size="9" fill="#0B1E3F">R</text><text x="170" y="80" font-size="9" fill="#0B1E3F">P</text></svg>', 7, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Why does a catalyst not change deltaH?', 'It provides an alternative pathway with lower Ea but the initial and final states are unchanged, so the enthalpy change is the same.', 8, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'State the calorimetry equation.', 'q = mc(deltaT). q in J, m in g, c = 4.18 J g^-1 K^-1 for water, deltaT in K. Enthalpy per mole = q / n.', 9, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Give Hess''s Law.', 'The total enthalpy change for a reaction is independent of route, provided initial and final conditions are the same; allows calculation of deltaH using known deltaH_f or deltaH_c.', 10, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Why are mean bond enthalpy calculations approximate?', 'Mean bond enthalpies are averaged across many compounds; the actual bond strength depends on the molecular environment.', 11, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'How does adding a catalyst change the Maxwell-Boltzmann distribution?', 'No change to the curve. The Ea line shifts left, so a larger fraction of molecules have E >= Ea.', 12, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Apply Le Chatelier: increase pressure on N2 + 3H2 <=> 2NH3.', 'Equilibrium shifts to fewer moles of gas (right, towards NH3), so yield increases.', 13, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Write Kc for 2A + B <=> 3C.', 'Kc = [C]^3 / ([A]^2 [B]).', 14, 'alevel'),
  ('Chemistry', 'OCR A', 'M3', 'Periodic Table and Energy', 'Why is BaSO4 used as the test for sulfate ions?', 'BaSO4 is highly insoluble, so adding Ba2+ to a sulfate solution gives a thick white ppt. Acidify with dilute HCl first to remove any carbonate.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Define homologous series.', 'A family of organic compounds with the same general formula and functional group, differing by CH2, with similar reactions and a smooth trend in physical properties.', 1, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Distinguish E/Z isomers.', 'When restricted rotation around C=C and each carbon bears two different groups, isomers exist where higher-priority groups are on the same (Z) or opposite (E) sides per CIP rules.', 2, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Give the equation for complete combustion of butane.', '2C4H10 + 13O2 -> 8CO2 + 10H2O.', 3, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Outline the mechanism for chlorination of methane (one propagation cycle).', 'Cl. + CH4 -> HCl + CH3.; CH3. + Cl2 -> CH3Cl + Cl. The Cl. is regenerated, propagating the chain.', 4, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Test for an alkene.', 'Decolourisation of orange/yellow bromine water to colourless via electrophilic addition forming a 1,2-dibromoalkane.', 5, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'State Markownikoff''s rule.', 'In HX addition to an unsymmetric alkene, H bonds to the carbon already having more H. The major product comes from the more stable carbocation.', 6, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'How are primary, secondary and tertiary alcohols distinguished using K2Cr2O7/H+?', 'Primary and secondary turn from orange to green; tertiary remains orange. Distil to obtain aldehyde (primary) vs ketone (secondary).', 7, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Give the conditions for dehydration of an alcohol to an alkene.', 'Concentrated H3PO4 (or concentrated H2SO4) catalyst, heated under reflux. Water is eliminated.', 8, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Sketch the SN2 transition state.', 'Pentavalent transition state with nucleophile and leaving group at 180 degrees. <svg viewBox="0 0 160 80" width="150" height="75" style="display:block;margin:6px auto"><circle cx="80" cy="40" r="6" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="2"/><text x="76" y="44" font-size="10" fill="#0B1E3F">C</text><line x1="74" y1="40" x2="40" y2="40" stroke="#0B1E3F" stroke-width="1.5" stroke-dasharray="3,2"/><line x1="86" y1="40" x2="120" y2="40" stroke="#0B1E3F" stroke-width="1.5" stroke-dasharray="3,2"/><text x="20" y="44" font-size="10" fill="#0B1E3F">Nu</text><text x="125" y="44" font-size="10" fill="#0B1E3F">X</text></svg>', 9, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Compare SN1 and SN2.', 'SN1: two-step via carbocation, rate = k[RX], racemisation, favoured by tertiary halogenoalkanes. SN2: one-step concerted, rate = k[RX][Nu], inversion, favoured by primary.', 10, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'How does ozone depletion involve CFCs?', 'UV breaks a C-Cl bond in CFCs producing Cl. radicals, which catalytically destroy O3: Cl. + O3 -> ClO. + O2; ClO. + O3 -> Cl. + 2O2.', 11, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'How does an alcohol form a halogenoalkane?', 'React with HX (e.g. NaBr/H2SO4 to give HBr in situ; or PCl3, PCl5, SOCl2) to substitute -OH for -X.', 12, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'How do mass spectra confirm a molecule?', 'The molecular ion M+ peak gives M_r; fragmentation gives clues to structure (e.g. m/z 29 = CHO+ aldehyde fragment, m/z 43 = CH3CO+ acyl fragment).', 13, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Match each IR absorption: 1715 cm^-1, 3300 broad, 3500 sharp.', '1715: C=O (aldehyde/ketone). 3300 broad: O-H (alcohol or carboxylic acid). 3500 sharp: N-H (amine).', 14, 'alevel'),
  ('Chemistry', 'OCR A', 'M4', 'Core Organic Chemistry', 'Define addition polymerisation.', 'Many alkene monomers join via breaking the C=C pi bond; a long saturated polymer chain forms with no by-product. e.g. nCH2=CH2 -> -(CH2-CH2)n-.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Define rate equation.', 'rate = k[A]^m[B]^n, where m and n are orders found experimentally; k is the rate constant. Overall order = m + n.', 1, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Determine order from concentration-time graphs.', 'Zero order: linear decline of [A] with time. First order: constant half-life. Second order: half-life doubles each successive time.', 2, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Linear form of the Arrhenius equation.', 'ln k = -Ea/(RT) + ln A. Plot ln k vs 1/T: gradient = -Ea/R, intercept = ln A.', 3, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Calculate Kp for 2NO2(g) <=> N2O4(g) given partial pressures.', 'Kp = p(N2O4) / p(NO2)^2. Units: Pa^-1 (or atm^-1, depending on units used).', 4, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Define a Bronsted-Lowry acid and base.', 'Acid: proton donor. Base: proton acceptor. Conjugate pairs differ by H+ (e.g. CH3COOH/CH3COO-).', 5, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'pH of 0.20 mol dm^-3 NaOH.', '[OH-] = 0.20; [H+] = Kw/[OH-] = 1e-14/0.20 = 5e-14; pH = -log10(5e-14) = 13.30.', 6, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Buffer principle: explain how CH3COOH/CH3COO- buffers added base.', 'OH- + CH3COOH -> CH3COO- + H2O. The weak acid provides protons to neutralise added OH-, so [H+] and pH change minimally.', 7, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Define lattice enthalpy of formation.', 'Enthalpy change when one mole of an ionic compound forms from its gaseous ions under standard conditions; always exothermic.', 8, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'State the Gibbs free energy equation and feasibility condition.', 'deltaG = deltaH - T(deltaS); reaction is feasible when deltaG <= 0.', 9, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Why are transition metal ions coloured?', 'Ligands split d-orbitals into two sets; electrons absorb visible photons (deltaE = hf) to be promoted; the complementary colour is transmitted.', 10, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Sketch an octahedral complex such as [Cu(H2O)6]2+.', 'Six ligands at 90 degrees around the central metal ion. <svg viewBox="0 0 120 120" width="110" height="110" style="display:block;margin:6px auto"><circle cx="60" cy="60" r="6" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="2"/><line x1="60" y1="54" x2="60" y2="20" stroke="#0B1E3F" stroke-width="1.5"/><line x1="60" y1="66" x2="60" y2="100" stroke="#0B1E3F" stroke-width="1.5"/><line x1="54" y1="60" x2="20" y2="60" stroke="#0B1E3F" stroke-width="1.5"/><line x1="66" y1="60" x2="100" y2="60" stroke="#0B1E3F" stroke-width="1.5"/><line x1="56" y1="56" x2="35" y2="40" stroke="#0B1E3F" stroke-width="1.5" stroke-dasharray="3,2"/><line x1="64" y1="64" x2="85" y2="80" stroke="#0B1E3F" stroke-width="1.5"/></svg>', 11, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Give the colour change for ligand substitution: [Cu(H2O)6]2+ + excess NH3.', 'Pale blue solution -> deep blue solution as 4 H2O are replaced to give [Cu(NH3)4(H2O)2]2+.', 12, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Define standard cell potential.', 'E_cell = E_red(cathode) - E_red(anode), measured under standard conditions (1 mol dm^-3 ions, 100 kPa, 298 K). Positive E_cell means thermodynamically feasible.', 13, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'How does a hydrogen-oxygen fuel cell work?', 'H2 oxidised at the anode (H2 -> 2H+ + 2e-); O2 reduced at the cathode (O2 + 4H+ + 4e- -> 2H2O); ions migrate via the electrolyte. Only product is water.', 14, 'alevel'),
  ('Chemistry', 'OCR A', 'M5', 'Physical Chemistry & Transition Elements', 'Why does the chelate effect favour multidentate ligands?', 'Substituting monodentate ligands by polydentate ones increases the number of free particles in solution, raising deltaS so deltaG is more negative.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Why does benzene undergo substitution rather than addition?', 'Addition would disrupt the delocalised pi system, losing the stability of resonance. Substitution preserves the aromatic ring. <svg viewBox="0 0 100 100" width="80" height="80" style="display:block;margin:6px auto"><polygon points="50,10 87,30 87,72 50,92 13,72 13,30" fill="none" stroke="#0B1E3F" stroke-width="2"/><circle cx="50" cy="51" r="20" fill="none" stroke="#0B1E3F" stroke-width="1.5"/></svg>', 1, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Conditions and electrophile for nitration of benzene.', 'concentrated HNO3 + concentrated H2SO4 at 50 C; electrophile is NO2+. H2SO4 + HNO3 -> NO2+ + HSO4- + H2O.', 2, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Outline Friedel-Crafts acylation.', 'CH3COCl + AlCl3 -> CH3CO+ + AlCl4-; the acylium ion attacks benzene; H+ regenerates AlCl3. Product: phenyl ketone.', 3, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Why are amines basic?', 'The N lone pair accepts H+. Aliphatic amines are more basic than NH3 (alkyl groups donate electrons); aromatic amines are weaker because the lone pair is delocalised into the ring.', 4, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'How is phenylamine made?', 'Reduce nitrobenzene with Sn + concentrated HCl, heat under reflux; add NaOH(aq) to liberate the free amine.', 5, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'What is a zwitterion and when does it form?', 'A dipolar ion of an amino acid with -NH3+ and -COO- and zero net charge. Forms at the isoelectric point pH.', 6, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Give the monomer used to form Nylon-6,6.', '1,6-diaminohexane + hexanedioic acid (or hexanedioyl dichloride) condense, releasing H2O (or HCl) to form amide links.', 7, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Outline nucleophilic addition of HCN to propanone.', 'CN- attacks the delta+ C of C=O; alkoxide intermediate is protonated; gives a 2-hydroxynitrile (a cyanohydrin) as a racemic mixture.', 8, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Distinguish aldehyde from ketone.', 'Tollens'' (Ag(NH3)2+) gives a silver mirror with aldehydes; Fehling''s gives brick-red Cu2O ppt with aliphatic aldehydes. Ketones do not react.', 9, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Give the test for a carbonyl group using Brady''s reagent.', '2,4-DNP gives an orange/yellow precipitate with both aldehydes and ketones. Pure crystallised derivative''s melting point identifies the original carbonyl.', 10, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Give the reaction of an acyl chloride with water.', 'CH3COCl + H2O -> CH3COOH + HCl. Vigorous; produces white steamy fumes of HCl.', 11, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'How many 13C NMR signals does propan-2-ol show?', '2 signals: CH3 (two equivalent) and CH (one). 13C NMR distinguishes by chemical shift.', 12, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'State the n+1 rule and what it tells you.', 'A 1H NMR signal is split into n+1 peaks by n equivalent neighbouring (non-equivalent) hydrogens, identifying the number of adjacent H atoms.', 13, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'What does a D2O shake confirm?', 'OH or NH protons exchange with D and disappear from the 1H NMR spectrum, confirming exchangeable protons.', 14, 'alevel'),
  ('Chemistry', 'OCR A', 'M6', 'Organic Chemistry & Analysis', 'Outline the use of GC-MS in forensic analysis.', 'GC separates the components of a mixture by retention time; the mass spectrometer identifies each by its fragmentation pattern, giving both quantification and identification at trace levels.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Give the relative charges and masses of proton, neutron, electron.', 'Proton: +1, mass 1. Neutron: 0, mass 1. Electron: -1, mass 1/1836 (~0).', 1, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Define isotopes.', 'Atoms of the same element with the same number of protons but different numbers of neutrons; same chemical properties, different mass.', 2, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Describe the four stages of TOF mass spectrometry.', 'Ionisation (electron impact or electrospray), acceleration to constant kinetic energy, ion drift, and detection. m/z is calculated from time of flight.', 3, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Explain why first ionisation energy decreases down a group.', 'Atomic radius increases and shielding rises, outweighing the larger nuclear charge, so the outer electron is held less strongly.', 4, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Give the electron configuration of Cr and Cu.', 'Cr: [Ar] 3d5 4s1; Cu: [Ar] 3d10 4s1. Half-filled and fully-filled d sub-shells are extra stable.', 5, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Calculate the mass of NaOH needed for 250 cm3 of 0.100 mol dm^-3 solution.', 'n = c x V = 0.100 x 0.250 = 0.025 mol. m = n x M_r = 0.025 x 40 = 1.00 g.', 6, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'State Avogadro''s constant and use it to find molecules in 0.5 mol H2O.', '6.02 x 10^23 mol^-1. 0.5 mol = 3.01 x 10^23 molecules.', 7, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Define atom economy and percentage yield.', 'Atom economy = (M_r product / sum of M_r all products) x 100. % yield = (actual moles product / theoretical moles) x 100. Sustainable processes maximise both.', 8, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'How does VSEPR predict shape?', 'Electron pairs around a central atom repel each other and arrange to minimise repulsion. Lone pairs repel more than bonding pairs, distorting bond angles.', 9, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Sketch the bent shape of H2O and give bond angle.', 'Bent (V-shaped); H-O-H = 104.5 degrees. <svg viewBox="0 0 120 80" width="110" height="75" style="display:block;margin:6px auto"><circle cx="60" cy="30" r="6" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="2"/><text x="55" y="34" font-size="10" fill="#0B1E3F">O</text><line x1="55" y1="35" x2="25" y2="60" stroke="#0B1E3F" stroke-width="2"/><line x1="65" y1="35" x2="95" y2="60" stroke="#0B1E3F" stroke-width="2"/><text x="15" y="72" font-size="10" fill="#0B1E3F">H</text><text x="95" y="72" font-size="10" fill="#0B1E3F">H</text></svg>', 10, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Why is graphite a good conductor of electricity?', 'Each carbon has three covalent bonds in a layer, leaving one delocalised electron per atom that moves between layers, conducting current parallel to the layers.', 11, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Compare electrical conductivity of NaCl in three states.', 'Solid: no conduction (ions fixed). Molten or aqueous: conducts (ions free to move and carry charge).', 12, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'List the three intermolecular forces from weakest to strongest.', 'London (induced dipole-dipole) < permanent dipole-dipole < hydrogen bonding.', 13, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Why is H-bonding only between H and N, O or F?', 'These elements are highly electronegative and small; the H-X bond is very polar and the lone pair on X is concentrated, allowing strong H-bond formation.', 14, 'alevel'),
  ('Chemistry', 'OCR B', 'S1', 'Foundations of Chemistry', 'Why does diamond have a very high melting point?', 'Each carbon is covalently bonded to four others in a tetrahedral giant covalent lattice; melting requires breaking strong covalent bonds throughout the structure.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Define standard conditions for enthalpy.', '100 kPa pressure, 298 K temperature, all substances in their standard states, with solutions at 1 mol dm^-3.', 1, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Define standard enthalpy of combustion.', 'The enthalpy change when one mole of a substance is completely burned in oxygen under standard conditions.', 2, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Why does coffee-cup calorimetry of combustion underestimate deltaH?', 'Heat losses to surroundings, incomplete combustion, evaporation, non-standard conditions, and heat absorbed by the apparatus reduce the recorded temperature rise.', 3, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'State Hess''s Law.', 'The total enthalpy change is independent of the route taken, provided initial and final conditions are the same.', 4, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Why is calculated deltaH from mean bond enthalpies approximate?', 'Mean bond enthalpies are averaged across many molecules; actual bond strengths depend on the molecular environment.', 5, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Sketch a Born-Haber cycle for NaCl.', 'Steps: atomisation of Na, ionisation of Na, atomisation of 1/2Cl2, electron affinity of Cl, lattice formation. Sum equals deltaH_f. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="10" y1="100" x2="190" y2="100" stroke="#0B1E3F" stroke-width="1"/><line x1="20" y1="100" x2="20" y2="80" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="80" x2="60" y2="80" stroke="#0B1E3F" stroke-width="1.5"/><line x1="60" y1="80" x2="60" y2="40" stroke="#0B1E3F" stroke-width="1.5"/><line x1="60" y1="40" x2="100" y2="40" stroke="#0B1E3F" stroke-width="1.5"/><line x1="100" y1="40" x2="100" y2="20" stroke="#0B1E3F" stroke-width="1.5"/><line x1="100" y1="20" x2="140" y2="20" stroke="#0B1E3F" stroke-width="1.5"/><line x1="140" y1="20" x2="140" y2="100" stroke="#0B1E3F" stroke-width="1.5"/><text x="22" y="115" font-size="9" fill="#0B1E3F">Na(s)</text><text x="135" y="115" font-size="9" fill="#0B1E3F">NaCl(s)</text><text x="100" y="14" font-size="8" fill="#0B1E3F">gas ions</text></svg>', 6, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Why is the lattice enthalpy of MgO much larger than NaCl?', 'Mg2+ and O2- have larger charges (2+/2-) and smaller radii, so the electrostatic attraction in the lattice is much stronger.', 7, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Define entropy.', 'A measure of the dispersal of energy in a system; higher entropy = more disorder/ways to arrange particles. Symbol S, units J K^-1 mol^-1.', 8, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Predict the sign of deltaS for H2O(l) -> H2O(g).', 'Positive; entropy of gas >> entropy of liquid, so disorder increases significantly.', 9, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'State the Gibbs equation and feasibility condition.', 'deltaG = deltaH - T(deltaS); a reaction is thermodynamically feasible when deltaG <= 0.', 10, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Sketch the Maxwell-Boltzmann distribution and label area > Ea.', 'Skewed curve; only molecules with E >= Ea (right tail shaded) can react. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="100" x2="190" y2="100" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="100" x2="20" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M20,100 Q60,15 100,55 T190,98" fill="none" stroke="#0B1E3F" stroke-width="2"/><line x1="130" y1="100" x2="130" y2="20" stroke="#0B1E3F" stroke-width="1" stroke-dasharray="3,2"/><text x="120" y="14" font-size="9" fill="#0B1E3F">Ea</text></svg>', 11, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Why does a small temperature rise greatly increase rate?', 'Exponential dependence in Arrhenius: a small increase in T greatly increases the fraction of molecules with E >= Ea, so successful collision rate rises sharply.', 12, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'How does a heterogeneous catalyst work?', 'Reactants adsorb onto the catalyst surface (active sites); bonds are weakened, reactants react in the correct orientation, and products desorb. Lowers Ea without being consumed.', 13, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'Give the units of k for a second-order reaction.', 'mol^-1 dm^3 s^-1.', 14, 'alevel'),
  ('Chemistry', 'OCR B', 'S2', 'Energetics and Kinetics', 'State the linear form of the Arrhenius equation.', 'ln k = -Ea/(RT) + ln A. Plot ln k vs 1/T: gradient = -Ea/R, intercept = ln A.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Define dynamic equilibrium.', 'Forward and reverse reactions occur at equal rates in a closed system, so concentrations of all species remain constant.', 1, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'State Le Chatelier''s principle.', 'When a system at equilibrium is disturbed by a change in conditions, the position of equilibrium shifts to oppose the change.', 2, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'How does increasing pressure affect 2NO2 <=> N2O4?', 'Equilibrium shifts to fewer moles of gas (right, towards N2O4); the colour fades from brown to lighter as more colourless N2O4 forms.', 3, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Why does a catalyst not change the equilibrium yield?', 'It speeds up the forward and reverse reactions equally, so equilibrium is reached faster but the position and Kc are unchanged.', 4, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Write Kp for N2(g) + 3H2(g) <=> 2NH3(g).', 'Kp = (p(NH3))^2 / (p(N2) x (p(H2))^3). Units depend on pressure unit (e.g. Pa^-2 or atm^-2).', 5, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Define a Bronsted-Lowry acid and base.', 'Acid: proton donor. Base: proton acceptor. e.g. HCl + NH3 -> NH4+ + Cl-: HCl is the acid, NH3 the base.', 6, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Calculate pH of 0.020 mol dm^-3 HCl.', 'Strong acid: [H+] = 0.020. pH = -log10(0.020) = 1.70.', 7, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Define Ka and pKa.', 'Ka = [H+][A-]/[HA] for HA <=> H+ + A-. pKa = -log10(Ka). Smaller pKa = stronger acid.', 8, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Calculate pH of 0.10 mol dm^-3 ethanoic acid (Ka = 1.8 x 10^-5).', '[H+] = sqrt(Ka x [HA]) = sqrt(1.8e-5 x 0.10) ~ 1.34e-3. pH ~ 2.87.', 9, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'State the value of Kw at 298 K.', 'Kw = [H+][OH-] = 1.00 x 10^-14 mol^2 dm^-6. In pure water [H+] = [OH-] = 10^-7, pH = 7.', 10, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'How does a buffer mixture of CH3COOH and CH3COO- resist added acid?', 'Added H+ + CH3COO- -> CH3COOH; the conjugate base mops up the H+, so [H+] and pH change very little.', 11, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'State the Henderson-Hasselbalch equation.', 'pH = pKa + log10([A-]/[HA]). When [A-] = [HA], pH = pKa (the half-equivalence point).', 12, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Sketch a strong acid + weak base titration curve.', 'pH starts low, rises slowly through buffer region, and equivalence point is < 7 (acidic salt). <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="105" x2="190" y2="105" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="105" x2="20" y2="10" stroke="#0B1E3F" stroke-width="1.5"/><path d="M20,95 L80,80 L100,55 L160,40 L180,38" fill="none" stroke="#0B1E3F" stroke-width="2"/><circle cx="95" cy="65" r="2" fill="#0B1E3F"/><text x="2" y="60" font-size="9" fill="#0B1E3F">pH</text></svg>', 13, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Choose an indicator for HCl + NH3 titration.', 'Methyl orange (pH 3.1-4.4); equivalence pH < 7 because NH4Cl is acidic. Phenolphthalein would change colour too late.', 14, 'alevel'),
  ('Chemistry', 'OCR B', 'S3', 'Equilibrium and Acid-Base', 'Why is enthalpy of neutralisation less exothermic for a weak acid than a strong acid?', 'Some energy is needed to fully ionise the weak acid before neutralisation, so net heat released per mole of water formed is smaller.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Define a homologous series.', 'A series of organic compounds with the same general formula and functional group, differing by CH2, with similar reactions and a smooth trend in physical properties.', 1, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Distinguish E/Z isomers using CIP priority.', 'Z: higher-priority groups on the same side of C=C; E: higher-priority groups on opposite sides. Restricted rotation around C=C is the source of isomerism.', 2, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Define a chiral centre.', 'A carbon atom with four different groups attached, giving rise to two non-superimposable mirror-image enantiomers.', 3, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Describe the boiling point trend in the alkane homologous series.', 'Boiling point increases with chain length: longer alkanes have more electrons and larger contact surface, so London forces are stronger.', 4, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Give the propagation steps for the chlorination of methane.', 'Cl. + CH4 -> HCl + CH3.; CH3. + Cl2 -> CH3Cl + Cl. Cl. is regenerated, propagating the chain.', 5, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'State the test for an alkene.', 'Decolourisation of bromine water from orange/yellow to colourless via electrophilic addition forming a 1,2-dibromoalkane.', 6, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'State Markownikoff''s rule.', 'In HX addition to an unsymmetric alkene, H bonds to the carbon already bearing more H. The major product comes from the more stable (more substituted) carbocation.', 7, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Sketch the addition polymer of propene.', 'Repeat unit -(CH2-CH(CH3))- joined together. <svg viewBox="0 0 200 60" width="180" height="55" style="display:block;margin:6px auto"><line x1="20" y1="30" x2="50" y2="30" stroke="#0B1E3F" stroke-width="2"/><line x1="50" y1="30" x2="80" y2="30" stroke="#0B1E3F" stroke-width="2"/><line x1="80" y1="30" x2="110" y2="30" stroke="#0B1E3F" stroke-width="2"/><line x1="110" y1="30" x2="140" y2="30" stroke="#0B1E3F" stroke-width="2"/><line x1="140" y1="30" x2="170" y2="30" stroke="#0B1E3F" stroke-width="2"/><line x1="50" y1="30" x2="50" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><text x="42" y="12" font-size="10" fill="#0B1E3F">CH3</text><line x1="110" y1="30" x2="110" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><text x="102" y="12" font-size="10" fill="#0B1E3F">CH3</text><text x="180" y="34" font-size="10" fill="#0B1E3F">]n</text></svg>', 8, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'How are primary, secondary and tertiary alcohols classified?', 'By the number of carbons attached to the C bonded to OH: 1 = primary, 2 = secondary, 3 = tertiary.', 9, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Reagents to oxidise primary alcohol to aldehyde and to carboxylic acid.', 'Aldehyde: K2Cr2O7/H2SO4, distil out as it forms. Carboxylic acid: K2Cr2O7/H2SO4, heat under reflux with excess oxidant.', 10, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'State the conditions for esterification.', 'Carboxylic acid + alcohol with concentrated H2SO4 catalyst, heated under reflux: an equilibrium giving an ester + water.', 11, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Compare SN1 and SN2.', 'SN2: one-step concerted, rate = k[RX][Nu], inversion, primary halogenoalkanes. SN1: two-step via carbocation, rate = k[RX], racemisation, tertiary halogenoalkanes.', 12, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Why does C-I react faster than C-Cl in nucleophilic substitution?', 'C-I has the lowest bond enthalpy and breaks most easily; bond strength dominates over polarity in determining rate.', 13, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'Distinguish substitution from elimination using KOH.', 'Aqueous KOH: nucleophilic substitution -> alcohol. Ethanolic KOH: elimination -> alkene + water + KX.', 14, 'alevel'),
  ('Chemistry', 'OCR B', 'S4', 'Organic Chemistry', 'How is an alcohol converted to a halogenoalkane?', 'React with HX (e.g. NaBr/concentrated H2SO4 generates HBr in situ; or use PCl3/PCl5/SOCl2) to substitute -OH for -X.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Define oxidation and reduction in terms of electrons.', 'Oxidation: loss of electrons (oxidation state increases). Reduction: gain of electrons (oxidation state decreases). Mnemonic: OIL RIG.', 1, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Assign oxidation states in MnO4-.', 'O = -2; sum = -1; so Mn = -1 - 4(-2) = +7. Permanganate ion has Mn(VII).', 2, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Balance: MnO4- + Fe2+ + H+ -> Mn2+ + Fe3+ + H2O.', 'MnO4- + 8H+ + 5Fe2+ -> Mn2+ + 5Fe3+ + 4H2O. Combine half-equations balancing electrons (5 e- per Mn).', 3, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Define standard electrode potential.', 'The voltage of a half-cell measured against a standard hydrogen electrode under standard conditions (1 mol dm^-3 ions, 100 kPa, 298 K).', 4, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'How is cell EMF calculated?', 'E_cell = E(more positive electrode) - E(more negative electrode). Positive E_cell -> reaction is feasible under standard conditions.', 5, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Sketch a galvanic cell with Zn and Cu electrodes.', 'Zn(s) | Zn2+ || Cu2+ | Cu(s); voltmeter between them; salt bridge between solutions. <svg viewBox="0 0 200 100" width="180" height="90" style="display:block;margin:6px auto"><rect x="20" y="40" width="60" height="50" fill="none" stroke="#0B1E3F" stroke-width="1.5"/><rect x="120" y="40" width="60" height="50" fill="none" stroke="#0B1E3F" stroke-width="1.5"/><line x1="50" y1="40" x2="50" y2="20" stroke="#0B1E3F" stroke-width="2"/><line x1="150" y1="40" x2="150" y2="20" stroke="#0B1E3F" stroke-width="2"/><line x1="50" y1="20" x2="150" y2="20" stroke="#0B1E3F" stroke-width="1.5"/><circle cx="100" cy="20" r="6" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="1.5"/><text x="96" y="24" font-size="9" fill="#0B1E3F">V</text><line x1="80" y1="50" x2="120" y2="50" stroke="#0B1E3F" stroke-width="1.5" stroke-dasharray="4,3"/><text x="35" y="98" font-size="9" fill="#0B1E3F">Zn</text><text x="135" y="98" font-size="9" fill="#0B1E3F">Cu</text></svg>', 6, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Why might a feasible reaction not occur?', 'Activation energy may be too high (kinetics), or non-standard conditions shift the actual potential. E_cell is purely thermodynamic.', 7, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Outline a hydrogen-oxygen fuel cell.', 'Anode: H2 -> 2H+ + 2e-. Cathode: 1/2 O2 + 2H+ + 2e- -> H2O. Overall: 2H2 + O2 -> 2H2O. EMF ~ 1.23 V; only product water.', 8, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Define a transition metal.', 'A d-block element forming at least one stable ion with a partially filled d sub-shell. Sc and Zn are excluded.', 9, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'List the four characteristic properties of transition metals.', 'Variable oxidation states; coloured ions; catalytic activity; complex ion formation.', 10, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Why are most transition metal complexes coloured?', 'Ligands split d orbitals into two energy levels; electrons absorb visible photons (deltaE = hf) to be promoted, and the complementary colour is transmitted.', 11, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Give examples of monodentate, bidentate, and hexadentate ligands.', 'Monodentate: H2O, NH3, Cl-, CN-. Bidentate: ethane-1,2-diamine (en), ethanedioate. Hexadentate: EDTA4-.', 12, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Give shape and bond angle of [Cu(H2O)6]2+ and [CuCl4]2-.', '[Cu(H2O)6]2+: octahedral, 90 degrees. [CuCl4]2-: tetrahedral, 109.5 degrees (Cl- too bulky for 6 ligands).', 13, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'Give the colour change for adding excess NH3 to Cu2+(aq).', 'Pale blue solution -> pale blue ppt of Cu(OH)2(H2O)4 -> deep blue solution of [Cu(NH3)4(H2O)2]2+ in excess ammonia.', 14, 'alevel'),
  ('Chemistry', 'OCR B', 'S5', 'Redox & Transition Metals', 'How does a colorimeter measure transition metal ion concentration?', 'Calibrate with standards to make a calibration curve of absorbance vs concentration; measure unknown''s absorbance and read off [ion]. Uses the wavelength of maximum absorption.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Describe the structure of benzene.', 'Planar hexagonal ring of 6 sp2 carbons; each contributes one electron to a delocalised pi system above and below the ring. <svg viewBox="0 0 100 100" width="90" height="90" style="display:block;margin:6px auto"><polygon points="50,10 87,30 87,72 50,92 13,72 13,30" fill="none" stroke="#0B1E3F" stroke-width="2"/><circle cx="50" cy="51" r="20" fill="none" stroke="#0B1E3F" stroke-width="1.5"/></svg>', 1, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Why does benzene undergo electrophilic substitution rather than addition?', 'Substitution preserves the delocalised pi system; addition would disrupt it and lose aromatic stability (~152 kJ mol^-1).', 2, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Conditions and electrophile for nitration of benzene.', 'concentrated HNO3 + concentrated H2SO4 at 50 C; the electrophile is NO2+. Product: nitrobenzene.', 3, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Outline the nucleophilic addition of HCN to ethanal.', 'CN- attacks delta+ C of C=O; alkoxide forms; protonation gives a 2-hydroxynitrile (cyanohydrin) as a racemic mixture if a chiral C is created.', 4, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Distinguish aldehydes from ketones with two tests.', '2,4-DNP gives orange/yellow ppt with both. Tollens'' (silver mirror) and Fehling''s (brick-red Cu2O) react only with aldehydes.', 5, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Compare reactivity of acyl chlorides and carboxylic acids with alcohols.', 'Acyl chloride + alcohol -> ester + HCl, fast and complete. Carboxylic acid + alcohol -> ester + H2O, slow equilibrium needing H2SO4 catalyst.', 6, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Why are aromatic amines weaker bases than aliphatic amines?', 'In phenylamine the N lone pair delocalises into the ring, reducing its availability to accept H+. Alkyl groups in aliphatic amines push electron density onto N, enhancing basicity.', 7, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Define an amino acid zwitterion.', 'A dipolar form of an amino acid with -NH3+ and -COO-, no overall charge, formed at the isoelectric point.', 8, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Compare addition and condensation polymers.', 'Addition: monomers contain C=C; no by-product, e.g. poly(ethene). Condensation: two functional groups react with loss of a small molecule (H2O or HCl), e.g. polyesters and polyamides.', 9, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Give the M_r and key fragment of butan-2-one (CH3COC2H5).', 'M_r = 72. M+ = 72; alpha-cleavage gives m/z 43 (CH3CO+) and m/z 57 (C2H5CO+); m/z 29 (C2H5+).', 10, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Identify functional group from IR: very broad 2500-3300 cm^-1 + C=O ~1710.', 'Carboxylic acid: broad O-H of acid plus C=O.', 11, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'How many 1H NMR signals does ethanol show after a D2O shake?', 'Two: CH3 and CH2. The OH proton exchanges with D and disappears.', 12, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'State the n+1 rule for 1H NMR splitting.', 'A signal is split into n+1 peaks by n equivalent neighbouring (non-equivalent) hydrogen atoms; identifies the number of adjacent H.', 13, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'What is the role of TMS in NMR?', 'Reference at 0 ppm; gives a single sharp peak, chemically inert, volatile, and contains 12 equivalent H. All other shifts are quoted relative to it.', 14, 'alevel'),
  ('Chemistry', 'OCR B', 'S6', 'Advanced Organic & Analysis', 'Explain how HPLC separates compounds.', 'Sample is forced under high pressure through a column packed with a solid stationary phase; components partition between mobile and stationary phases at different rates, separating by retention time.', 15, 'alevel');
